# PowerShell Profile Diagnostic Script
# Run this to see what's broken

Write-Host "`n=== POWERSHELL PROFILE DIAGNOSTIC ===" -ForegroundColor Cyan

# 1. Check profile location
Write-Host "`n[1] Profile Locations:" -ForegroundColor Yellow
Write-Host "  CurrentUserAllHosts: $($PROFILE.CurrentUserAllHosts)"
Write-Host "  CurrentUserCurrentHost: $($PROFILE.CurrentUserCurrentHost)"

# 2. Check if profile exists
Write-Host "`n[2] Profile Status:" -ForegroundColor Yellow
$profiles = @(
    @{Name="AllHosts"; Path=$PROFILE.CurrentUserAllHosts},
    @{Name="CurrentHost"; Path=$PROFILE.CurrentUserCurrentHost}
)

foreach ($p in $profiles) {
    if (Test-Path $p.Path) {
        $size = (Get-Item $p.Path).Length
        Write-Host "  ✓ $($p.Name): EXISTS ($size bytes)" -ForegroundColor Green
        Write-Host "    Content preview:"
        Get-Content $p.Path -TotalCount 5 | ForEach-Object { Write-Host "    $_" -ForegroundColor Gray }
    } else {
        Write-Host "  ✗ $($p.Name): MISSING" -ForegroundColor Red
    }
}

# 3. Check environment variables
Write-Host "`n[3] Suspicious Environment Variables:" -ForegroundColor Yellow
$suspicious = Get-ChildItem Env: | Where-Object { 
    $_.Name -like "*COPILOT*" -or 
    $_.Name -like "*API*" -or
    $_.Name -like "*OPENAI*" -or
    $_.Name -like "*ANTHROPIC*"
}
if ($suspicious) {
    foreach ($var in $suspicious) {
        Write-Host "  ! $($var.Name) = $($var.Value)" -ForegroundColor Yellow
    }
} else {
    Write-Host "  ✓ None found" -ForegroundColor Green
}

# 4. Current prompt function
Write-Host "`n[4] Current Prompt Function:" -ForegroundColor Yellow
if (Get-Command prompt -ErrorAction SilentlyContinue) {
    Write-Host "  Status: DEFINED" -ForegroundColor Green
    Write-Host "  Definition:"
    (Get-Command prompt).Definition.Split("`n") | Select-Object -First 10 | ForEach-Object { 
        Write-Host "    $_" -ForegroundColor Gray 
    }
} else {
    Write-Host "  Status: NOT DEFINED (using default)" -ForegroundColor Red
}

# 5. PowerShell version
Write-Host "`n[5] PowerShell Info:" -ForegroundColor Yellow
Write-Host "  Version: $($PSVersionTable.PSVersion)"
Write-Host "  Edition: $($PSVersionTable.PSEdition)"
Write-Host "  OS: $($PSVersionTable.OS)"

# 6. Check for backup files
Write-Host "`n[6] Backup Files:" -ForegroundColor Yellow
