        "$HOME/SSoT_vault"*) echo "📚|ssot-hub" ;;
        "$HOME/reality"*) echo "🧭|reality-hub" ;;
        *) git rev-parse --is-inside-work-tree >/dev/null 2>&1 && echo "🌿|git-hub" || echo "•|no-hub" ;;
    esac
}
reduce_path() { echo "${PWD/#$HOME/~}" | sed -E 's|/([^/]{1})[^/]+/|/\1…/|g'; }
git_branch() { git rev-parse --abbrev-ref HEAD 2>/dev/null; }
build_prompt() { PS1="$(hub_info) | $(reduce_path) | $(git_branch)\n❯ "; }
PROMPT_COMMAND=build_prompt
ENV=~/.shrc
export ENV
EOF
